css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; display: flex; justify-content: center; padding: 40px 20px; min-height: 100vh; }
.app { width: 100%; max-width: 420px; }
h1 { font-size: 26px; font-weight: 800; text-align: center; margin-bottom: 8px; }
.subtitle { text-align: center; color: rgba(255,255,255,0.4); font-size: 13.5px; margin-bottom: 28px; }
.unit-toggle { display: flex; gap: 6px; background: rgba(255,255,255,0.04); border-radius: 14px; padding: 5px; margin-bottom: 24px; }
.unit-toggle button { flex: 1; background: transparent; border: none; color: rgba(255,255,255,0.5); padding: 11px; border-radius: 10px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.unit-toggle button.active { background: rgba(34,197,94,0.15); color: #4ade80; }
.form { display: flex; gap: 16px; margin-bottom: 28px; }
.field { flex: 1; }
.field label { display: block; font-size: 13px; font-weight: 700; color: rgba(255,255,255,0.5); margin-bottom: 8px; }
.input-row { display: flex; align-items: center; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 12px; padding: 4px 14px; }
.input-row input { flex: 1; background: transparent; border: none; color: white; font-size: 22px; font-weight: 700; padding: 12px 0; outline: none; }
.input-row span { font-size: 13px; color: rgba(255,255,255,0.4); font-weight: 700; }
.result { display: flex; flex-direction: column; align-items: center; margin-bottom: 28px; }
.result-circle { width: 160px; height: 160px; border-radius: 50%; background: rgba(74,222,128,0.1); border: 3px solid #4ade80; display: flex; flex-direction: column; align-items: center; justify-content: center; margin-bottom: 16px; transition: 0.3s; }
.bmi-value { font-size: 40px; font-weight: 800; }
.bmi-label { font-size: 12px; color: rgba(255,255,255,0.4); font-weight: 700; }
.result-category { font-size: 18px; font-weight: 800; }
.scale { margin-bottom: 28px; }
.scale-bar { display: flex; height: 10px; border-radius: 999px; overflow: hidden; position: relative; margin-bottom: 8px; }
.scale-segment.under { background: #38bdf8; }
.scale-segment.normal { background: #4ade80; }
.scale-segment.over { background: #facc15; }
.scale-segment.obese { background: #f87171; }
.scale-marker { position: absolute; top: -4px; width: 4px; height: 18px; background: white; border-radius: 2px; left: 25%; transition: left 0.3s; }
.scale-labels { display: flex; justify-content: space-between; font-size: 11px; color: rgba(255,255,255,0.4); font-weight: 600; }
.info-cards { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; }
.info-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); border-radius: 12px; padding: 14px; display: flex; justify-content: space-between; align-items: center; font-size: 13px; }
.ic-label { font-weight: 700; color: rgba(255,255,255,0.7); }
.ic-range { color: rgba(255,255,255,0.4); font-weight: 600; font-size: 12px; }

js:
let unit = 'metric';

function setUnit(btn, u) {
  unit = u;
  document.querySelectorAll('.unit-toggle button').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  if (u === 'metric') {
    document.getElementById('weightUnit').textContent = 'kg';
    document.getElementById('heightUnit').textContent = 'cm';
    document.getElementById('weight').value = 70;
    document.getElementById('height').value = 175;
  } else {
    document.getElementById('weightUnit').textContent = 'lb';
    document.getElementById('heightUnit').textContent = 'in';
    document.getElementById('weight').value = 154;
    document.getElementById('height').value = 69;
  }
  calculate();
}

function calculate() {
  let weight = parseFloat(document.getElementById('weight').value) || 0;
  let height = parseFloat(document.getElementById('height').value) || 0;
  if (weight <= 0 || height <= 0) return;

  let weightKg = weight;
  let heightM = height / 100;
  if (unit === 'imperial') {
    weightKg = weight * 0.453592;
    heightM = (height * 2.54) / 100;
  }

  const bmi = weightKg / (heightM * heightM);
  document.getElementById('bmiValue').textContent = bmi.toFixed(1);

  const circle = document.getElementById('resultCircle');
  const category = document.getElementById('resultCategory');
  const marker = document.getElementById('scaleMarker');

  let color, label, markerPos;
  if (bmi < 18.5) { color = '#38bdf8'; label = 'Zayıf'; markerPos = (bmi / 18.5) * 18.5; }
  else if (bmi < 25) { color = '#4ade80'; label = 'Normal Kilolu'; markerPos = 18.5 + ((bmi - 18.5) / 6.5) * 6.5; }
  else if (bmi < 30) { color = '#facc15'; label = 'Kilolu'; markerPos = 25 + ((bmi - 25) / 5) * 5; }
  else { color = '#f87171'; label = 'Obez'; markerPos = Math.min(30 + ((bmi - 30) / 10) * 70, 100); }

  circle.style.borderColor = color;
  circle.style.background = color + '1a';
  category.textContent = label;
  category.style.color = color;
  marker.style.left = Math.min(markerPos, 100) + '%';
}

calculate();
